    void Start()
    {
        dogs = new List<GameObject>();
        playerX = 3;
        playerY = 44;
        originX=0;
        originY=0;
        tileSize=4;
        score=0;
        dogLoop=0;
        Vector3 p=transform.position;
        p.x = originX + playerX * tileSize;
        p.z = originY + playerY * tileSize;
        transform.position = p;
        isMoving = false;
        for (int i = 0; i < level.GetLength(0); i++)
        {
            for (int j = 0; j < level.GetLength(1); j++)
            {
                GameObject tile = null;
                switch (level[i,j])
                {
                    case (int)tiles.empty:
                        continue;
                    case (int)tiles.jump:
                        tile = Instantiate(jumpTile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                        break;
                    case (int)tiles.blind:
                        tile = Instantiate(blindTile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                        break;
                    case (int)tiles.slow:
                        tile = Instantiate(slowTile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                        break;
                    case (int)tiles.child:
                        tile = Instantiate(childTile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                        break;
                    case (int)tiles.car1:
                        tile = Instantiate(car1Tile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                        break;
                    case (int)tiles.car2:
                        tile = Instantiate(car2Tile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                        break;
                    case (int)tiles.cone:
                        tile = Instantiate(coneTile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                        break;
                    case (int)tiles.road:
                        tile = Instantiate(roadTile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                        break;
                    case (int)tiles.final:
                        tile = Instantiate(roadTile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                        break;
                    case (int)tiles.spawn:
                        tile = Instantiate(roadTile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                        GameObject dog=Instantiate(dogObject, new Vector3(originX + i * tileSize, 0f, originY + j * tileSize), Quaternion.identity);
                        dog.SetActive(true);
                        dogs.Add(dog);
                        break;
                    case (int)tiles.buildR1:
                        int buildType = UnityEngine.Random.Range(1, 4);
                        switch (buildType)
                        {
                            case 1:
                                tile = Instantiate(build11Tile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                                break;
                            case 2:
                                tile = Instantiate(build12Tile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                                break;
                            case 3:
                                tile = Instantiate(build13Tile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                                break;
                        }
                        break;
                    case (int)tiles.buildR2:
                        int buildType2 = UnityEngine.Random.Range(1, 4);
                        switch (buildType2)
                        {
                            case 1:
                                tile = Instantiate(build21Tile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                                break;
                            case 2:
                                tile = Instantiate(build22Tile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                                break;
                            case 3:
                                tile = Instantiate(build23Tile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                                break;
                        }
                        break;
                    case (int)tiles.buildCorner:
                        tile = Instantiate(buildCornerTile, new Vector3(originX + i * tileSize, 0, originY + j * tileSize), Quaternion.identity);
                        break;
                }
                tile.SetActive(true);
            }
        }
    }
    void Update()
    {
        dogLoop+=Time.deltaTime;
        if(dogLoop > 2.0f)
        {
            dogLoop=0;
            foreach(GameObject dog in dogs)
            {
                if (dog == null) continue;
                float dirMag = (new Vector3(playerX * tileSize + originX, 0f, playerY * tileSize + originY) - dog.transform.position).magnitude;
                Vector3 dir = (new Vector3(playerX * tileSize + originX, 0f, playerY * tileSize + originY) - dog.transform.position).normalized;
                if (Mathf.Abs(dir.x) > Mathf.Abs(dir.z))
                {
                    dir.z = 0;
                    dir.x = Mathf.Sign(dir.x);
                }
                else
                {
                    dir.x = 0;
                    dir.z = Mathf.Sign(dir.z);
                }
                if (dirMag > 0.1f && dirMag < (5f * tileSize))
                {
                    dog.transform.rotation = Quaternion.LookRotation(dir);
                    int targetX=(int)((dog.transform.position.x+ dir.x * tileSize - originX) / tileSize);
                    int targetY=(int)((dog.transform.position.z+ dir.z * tileSize - originY) / tileSize);
                    if(canGoto(targetX, targetY) && (level[targetX, targetY] == (int)tiles.road||level[targetX, targetY] == (int)tiles.final||level[targetX, targetY] == (int)tiles.spawn||level[targetX, targetY] ==(int)tiles.blind))
                    {
                        bool closeDog=false;
                        foreach(GameObject d in dogs)
                        {
                            if (d == null) continue;
                            if (d == dog) continue;
                            if (Vector3.Distance(d.transform.position, new Vector3(targetX * tileSize + originX, 0f, targetY * tileSize + originY)) < 0.1f)
                            {
                                closeDog=true;
                                break;
                            }
                        }
                        if(!closeDog) dog.transform.position += dir * tileSize;
                    }
                }
                if (Vector3.Distance(dog.transform.position, new Vector3(playerX * tileSize + originX, 0f, playerY * tileSize + originY)) < 0.1f)
                {
                    ExplodeDog(dog);
                }
            }
        }
    }
    public void OnMove(InputActionReference moveDirection)
    {
        if (isMoving) return;
        int newX = playerX;
        int newY = playerY;
        Vector2 v = moveDirection.action.ReadValue<Vector2>();
        switch (v)
        {
            case Vector2 v2 when v2 == Vector2.up:
                newY += 1;
                break;
            case Vector2 v2 when v2 == Vector2.down:
                newY -= 1;
                break;
            case Vector2 v2 when v2 == Vector2.left:
                newX -= 1;
                break;
            case Vector2 v2 when v2 == Vector2.right:
                newX += 1;
                break;
            default:
                return;
        }
        if(canGoto(newX, newY) && level[newX, newY] == (int)tiles.jump)
        {
            if (canGoto(newX + (newX - playerX), newY + (newY - playerY)))
            {
            newX += (newX - playerX);
            newY += (newY - playerY);
            playerX = newX;
            playerY = newY;
            if(level[newX, newY] == (int)tiles.blind)
            {
                print("You stepped on a blind tile!");
            }
            StartCoroutine(Animate(newX, newY));
            print("Moved to: " + playerX + ", " + playerY);
            }
        }
        else if (canGoto(newX, newY))
        {
            playerX = newX;
            playerY = newY;
            if(level[newX, newY] == (int)tiles.blind)
            {
                print("You stepped on a blind tile!");
                StartCoroutine(Animate(newX, newY));
            }
            else if(level[newX, newY] == (int)tiles.slow)
            {
                StartCoroutine(Animate(newX, newY, 0.5f));
            }
            else if(level[newX, newY] == (int)tiles.final)
            {
                print("You Win!");
                StartCoroutine(Animate(newX, newY));
            }
            else if(level[newX, newY] == (int)tiles.child)
            {
                print("You stepped on a child tile!");
                StartCoroutine(Animate(newX, newY, 0.5f));
            }
            else StartCoroutine(Animate(newX, newY));
            print("Moved to: " + playerX + ", " + playerY);
        }
    }
    public IEnumerator Animate(int newX, int newY, float duration = 0.25f)
    {   
        isMoving = true;
        float elapsed = 0;
        Vector3 p=transform.position;
        Vector3 p0=p;
        p.x = originX + newX * tileSize;
        p.z = originY + newY * tileSize;
        while(elapsed < duration)
        {
            elapsed+=Time.deltaTime;
            transform.position = Vector3.Lerp(p0, p, (float)elapsed / duration);
            yield return null;
        }
        transform.position = p;
        foreach (GameObject dog in dogs)
        {
            if (dog == null) continue;
            if (Vector3.Distance(dog.transform.position, new Vector3(playerX * tileSize + originX, 0f, playerY * tileSize + originY)) < 0.1f)
            {
                ExplodeDog(dog);
            }
        }
        isMoving = false;
        StopCoroutine(Animate(newX, newY, duration));
    }
    public bool canGoto(int x, int y)
    {
        if (x < 0 || x >= level.GetLength(0) || y < 0 || y >= level.GetLength(1)) return false;
        if (level[x, y] == (int)tiles.empty||level[x, y] == (int)tiles.cone||level[x, y] == (int)tiles.car1||level[x, y] == (int)tiles.car2||level[x, y] == (int)tiles.buildR1||level[x, y] == (int)tiles.buildR2||level[x, y] == (int)tiles.buildCorner) return false;
        return true;
    }
    public void ExplodeDog(GameObject dog)
    {
        score--;
        Destroy(dog);
    }
}
